    }

    // Determine number of fields by counting commas in the first record
    int total_fields = 1;
    for (const char *p = csv_data[0]; *p != '\0'; p++) {
        if (*p == ',') {
            total_fields++;
        }
    }

    // Calculate record size (sum of field_sizes)
    long record_size = 0;
    for (int i = 0; i < total_fields; i++) {
        // Ensure field_sizes[i] is non-negative
        if (field_sizes[i] < 0) {
            return -1;
        }
        record_size += field_sizes[i];
        // Check for overflow
        if (record_size > INT_MAX) {
            return -1;
        }
    }

    // Calculate total buffer size
    long total_buffer_size = (long)record_count * record_size;
    if (total_buffer_size > INT_MAX) {
        return -1;
    }

    // Allocate memory for the buffer
    char *buffer = (char*)malloc(total_buffer_size);
    if (buffer == NULL) {
        return -1;
    }

    char *current = buffer;

    // Process each record
    for (int i = 0; i < record_count; i++) {
        // Handle NULL records by padding with spaces
        if (csv_data[i] == NULL) {
            for (int j = 0; j < total_fields; j++) {
                int field_size = field_sizes[j];
                memset(current, ' ', field_size);
                current += field_size;
            }
            continue;
        }

        char *start = csv_data[i];
        char *end = start;

        // Process each field in the record
        for (int j = 0; j < total_fields; j++) {
            // Find end of current field (comma or null terminator)
            end = start;
            while (*end != '\0' && *end != ',') {
                end++;
            }

            int field_len = end - start;
            int field_size = field_sizes[j];

            // Calculate copy length (truncate if field is too long)
            int copy_len = (field_len < field_size) ? field_len : field_size;

            // Copy field data
            memcpy(current, start, copy_len);

            // Pad with spaces if field is shorter than field_size
            if (field_len < field_size) {
                memset(current + copy_len, ' ', field_size - copy_len);
            }

            // Advance buffer pointer
            current += field_size;

            // Handle end of record
            if (*end == '\0') {
                // Pad remaining fields with spaces
                for (int k = j + 1; k < total_fields; k++) {
                    int remaining_size = field_sizes[k];
                    memset(current, ' ', remaining_size);
                    current += remaining_size;
                }
                break;
            } else {
                // Move to next field (skip comma)
                start = end + 1;
            }
        }
    }

    *parsed_buffer = buffer;
    return 0;
}
